            if op.left_lineno is not None:
                removed += 1
            if op.right_lineno is not None:
                added += 1
    if not removed and not added:
        return []
    else:
        return [_PrettyToken(_PrettyTokenType.HINT, '(also {} lines are deleted and {} lines are added...)'.format(removed, added))]


