def _decode_with_recovery(content: bytes) -> Tuple[List[_PrettyToken], str]:
    tokens = []
    try:
        text = content.decode()
    except UnicodeDecodeError as e:
        tokens.append(_PrettyToken(_PrettyTokenType.HINT, str(e)))
        text = content.decode(errors='replace')
    return tokens, text


