def _len_of_tokens(tokens: List[_PrettyToken]) -> int:
    result = 0
    for token in tokens:
        if token.type in (_PrettyTokenType.WHITESPACE, _PrettyTokenType.NEWLINE):
            result += len(_replace_whitespace(token.value).replace('\n', ''))
        else:
            result += len(token.value)
    return result


