def percentparse(s: str, format: str, table: Dict[str, str]) -> Optional[Dict[str, str]]:
    table = {key: '(?P<{}>{})'.format(key, value) for key, value in table.items()}
    used: Set[str] = set()
    pattern = ''
    for token in percentsplit(re.escape(format).replace('\\%', '%')):
