def _add_lines_around_diff_lines(a: str, b: str, *, ops: List[_LineDiffOp], size: int) -> List[_MergedDiffOp]:
    result: List[_MergedDiffOp] = []
    unused: List[_MergedDiffOp] = []
    use = 0
    for op in _reconstruct_entire_diff(a, b, ops=ops):
        if op.has_diff:
            result += unused[-size:]
            unused = []
            result.append(op)
            use = size
        else:
            if use:
                result.append(op)
                use -= 1
            else:
                unused.append(op)
    return result


