        if token.type == _PrettyTokenType.BODY:
            typ = _PrettyTokenType.BODY_HIGHLIGHT_RIGHT if is_right else _PrettyTokenType.BODY_HIGHLIGHT_LEFT
            tokens.append(_PrettyToken(typ, token.value))
        else:
            tokens.append(token)
